function UIIndieMain:onUpdatePlayerModel()
    local finalUrl = "/decoration/api/v1/decorations/{otherId}/using"
    finalUrl = string.gsub(finalUrl, "{otherId}", tostring(PlayerManager:getClientPlayer().userId))
    local params = {}
    WebService.asyncGet(finalUrl, params, function(data, code)
        if code == 1 then
            self:onUserActorChange(data)
        end
    end)
end

function UIIndieMain:onIndieDailyLogin()
    self.siChallengeRedPoint:SetVisible(true)
    self.siClassicRedPoint:SetVisible(true)
end

function UIIndieMain:onTick()
    local showAd = ClientHelper.getBoolPrefs("ShowVideoAd") and (not IsBeta)
    self:getChildWindow("BedWarNewIndieMain-bt_ad", GUIType.Button):SetVisible(showAd)
    self:getChildWindow("BedWarNewIndieMain-text_ad", GUIType.StaticText):SetVisible(showAd)

    local count = PlayerWallet.getMoneyByCoinId(Define.Money.DIAMOND)
    self.stCubeNum:SetText(tostring(count))
end

function UIIndieMain:onUserActorChange(data)
    self.awPlayer:RemoveActor()
    if Game:getPlayer():getSex() == 2 then
        self.awPlayer:SetActor1("girl.actor", "idle", 0)
    else
        self.awPlayer:SetActor1("boy.actor", "idle", 0)
    end

    for _, item in pairs(data) do
        if item["resourceId"] ~= nil then
            if item["typeId"] ~= 6 then
                local info = StringUtil.split(item["resourceId"], ".")
                self.awPlayer:UseBodyPart(info[1], info[2])
            else
                local info = StringUtil.split(item["resourceId"], "-")
                self.awPlayer:SetCustomColor({ tonumber(info[1] or 0) / 255, tonumber(info[2] or 0) / 255, tonumber(info[3] or 0) / 255, tonumber(info[4] or 0) / 255 })
            end
        end
    end
end

function UIIndieMain:onHallInfoUpdate(data)
    local level = data:getNumberParam("level")
    local curExp = data:getNumberParam("curExp")
    local maxExp = data:getNumberParam("maxExp")
    local key = data:getNumberParam("key")
    local isMax = data:getBoolParam("isMax")
    self.stLevel:SetText("LV." .. tostring(level))
    if not isMax then
        if maxExp > 0 then
            local expTxt = string.format("%d/%d", curExp, maxExp)
            self.stExpNum:SetVisible(true)
            self.stExpNum:SetText(expTxt)
            self.pbExpProgress:SetProgress(curExp / maxExp)
        else
            self.tvLevelExp:SetVisible(false)
            self.pbExpProgress:SetProgress(0)
        end
    else
        self.stExpNum:SetVisible(true)
        self.stExpNum:SetText("MAX")
        self.pbExpProgress:SetProgress(1)
    end
    self.stKeyNum:SetText(tostring(key))

    local user = UserManager.Instance():findUser(PlayerManager:getClientPlayer().userId)
    self.uivHeadIcon:setUrl(user.picUrl)
    self.stPlayerName:SetText(user.userName)
end

